(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[4498],{6153:(e,t,a)=>{"use strict";a.r(t),a.d(t,{data:()=>i});const i={key:"v-85559c76",path:"/git/initiate/repository/",title:"Create a Local Repository",lang:"en-US",frontmatter:{},excerpt:"",headers:[],filePathRelative:"git/initiate/repository/README.md",git:{updatedTime:162676698e4,contributors:[]}}},1094:(e,t,a)=>{"use strict";a.r(t),a.d(t,{default:()=>r});const i=(0,a(6252).uE)('<h1 id="create-a-local-repository" tabindex="-1"><a class="header-anchor" href="#create-a-local-repository" aria-hidden="true">#</a> Create a Local Repository</h1><p>โดยหากว่า project folder ใดต้องการทำการ Versioning โดยการใช้ Git ก็สามารถทำได้โดยการพิมพ์</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token function">git</span> init\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>โดยทำแล้ว จะมีโฟล์เดอร์ <code>.git</code> ขึ้นมาเพื่อจัดการ versioning โดยใน folder นั้นจะเก็บข้อมูลเกี่ยวกับการ commit เก่าๆ และปลายทาง ว่า remote อยู่ที่ไหน และอื่นๆที่เกียวข้องกับระบบ Git</p><p>และเมื่อทำการ init แล้วก็สามารถเรื่มทำงานและเพื่มไฟล์ได้เลย</p>',5),r={render:function(e,t){return i}}}}]);